-- Table structure for table `UNISEX`
--

DROP TABLE IF EXISTS `UNISEX`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `UNISEX` (
  `PROD_ID` int(11) NOT NULL,
  `UNI_DESCRIPT` varchar(50) NOT NULL,
  `MATERIAL` varchar(15) NOT NULL,
  `BRAND` varchar(15) NOT NULL,
  `FIT_TYPE` varchar(15) NOT NULL,
  `SIZES` varchar(20) NOT NULL,
  PRIMARY KEY (`PROD_ID`),
  CONSTRAINT `uni_fk` FOREIGN KEY (`PROD_ID`) REFERENCES `PRODUCTS` (`PROD_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
